    private static string MakeSafeFileName(string name)
    {
        foreach (var ch in Path.GetInvalidFileNameChars())
        {
            name = name.Replace(ch, '_');
        }
        return name;
    }

    private static string BuildChangePreview(DataTable data, int maxItems)
    {
        var lines = new List<string>();
        var total = 0;
        foreach (DataRow row in data.Rows)
        {
            if (row.RowState != DataRowState.Modified) continue;
            var id = data.Columns.Contains("ID") ? Convert.ToString(row["ID"], CultureInfo.InvariantCulture) : data.Rows.IndexOf(row).ToString(CultureInfo.InvariantCulture);
            for (var c = 1; c < data.Columns.Count; c++)
            {
                var original = row[c, DataRowVersion.Original];
                var current = row[c, DataRowVersion.Current];
                var originalText = Convert.ToString(original, CultureInfo.InvariantCulture) ?? string.Empty;
                var currentText = Convert.ToString(current, CultureInfo.InvariantCulture) ?? string.Empty;
                if (originalText == currentText) continue;

                total++;
                if (lines.Count < maxItems)
                {
                    lines.Add($"ID={id} {data.Columns[c].ColumnName}: {TrimPreview(originalText)} -> {TrimPreview(currentText)}");
                }
            }
        }

        if (total == 0) return "未发现单元格变更。";
        if (total > lines.Count) lines.Add($"……另有 {total - lines.Count} 项变更未显示。");
        return string.Join("\r\n", lines);
    }

    private static string TrimPreview(string value)
    {
        value = value.Replace("\r", "\\r").Replace("\n", "\\n");
        return value.Length > 40 ? value[..40] + "…" : value;
    }

    private void ValidateEditedCell(DataGridViewCellValidatingEventArgs e)
    {
        if (_dataGrid.ReadOnly || e.RowIndex < 0 || e.ColumnIndex <= 0) return;
        if (_dataGrid.Columns[e.ColumnIndex].ReadOnly) return;
        if (_dataGrid.DataSource is not DataTable data) return;
        var propertyName = _dataGrid.Columns[e.ColumnIndex].DataPropertyName;
        if (string.IsNullOrWhiteSpace(propertyName) || !data.Columns.Contains(propertyName)) return;
        if (data.Columns[propertyName]!.ExtendedProperties["FieldDefinition"] is not HexFieldDefinition field) return;

        var value = Convert.ToString(e.FormattedValue, CultureInfo.InvariantCulture) ?? string.Empty;
        var error = ValidateFieldValue(field, value);
        _dataGrid.Rows[e.RowIndex].Cells[e.ColumnIndex].ErrorText = error ?? string.Empty;
        if (error != null)
        {
            e.Cancel = true;
            SetStatus(error);
        }
    }

    private static string? ValidateFieldValue(HexFieldDefinition field, string value)
    {
        try
        {
            switch (field.Kind)
            {
                case HexFieldKind.UInt8:
                    return TryParseInteger(value, 0, byte.MaxValue, field.ColumnName);
                case HexFieldKind.UInt16:
                    return TryParseInteger(value, 0, ushort.MaxValue, field.ColumnName);
                case HexFieldKind.UInt32:
                    return TryParseUnsignedInteger(value, uint.MaxValue, field.ColumnName);
                case HexFieldKind.FixedString:
                    var bytes = EncodingService.GetGbkByteCount(value);
                    return bytes <= field.Size ? null : $"字段 {field.ColumnName} 超长：GBK {bytes} 字节，容量 {field.Size} 字节。";
                case HexFieldKind.RawBytes:
                    var parts = value.Replace("-", " ").Replace(",", " ").Replace("0x", "", StringComparison.OrdinalIgnoreCase)
                        .Split(new[] { ' ', '\t', '\r', '\n' }, StringSplitOptions.RemoveEmptyEntries);
                    if (parts.Length != field.Size) return $"字段 {field.ColumnName} 需要 {field.Size} 个十六进制字节。";
                    foreach (var part in parts) byte.Parse(part, NumberStyles.HexNumber, CultureInfo.InvariantCulture);
                    return null;
                default:
                    return null;
            }
        }
        catch (Exception ex)
        {
            return $"字段 {field.ColumnName} 无效：{ex.Message}";
        }
    }

    private static string? TryParseInteger(string value, long min, long max, string fieldName)
    {
        value = value.Trim();
        long parsed;
        if (value.StartsWith("0x", StringComparison.OrdinalIgnoreCase))
        {
            parsed = Convert.ToInt64(value[2..], 16);
        }
        else if (!long.TryParse(value, NumberStyles.Integer, CultureInfo.InvariantCulture, out parsed))
        {
            return $"字段 {fieldName} 需要整数。";
        }

        return parsed < min || parsed > max ? $"字段 {fieldName} 超出范围：{min}..{max}。" : null;
    }

    private static string? TryParseUnsignedInteger(string value, ulong max, string fieldName)
    {
        value = value.Trim();
        ulong parsed;
        if (value.StartsWith("0x", StringComparison.OrdinalIgnoreCase))
        {
            parsed = Convert.ToUInt64(value[2..], 16);
        }
        else if (!ulong.TryParse(value, NumberStyles.Integer, CultureInfo.InvariantCulture, out parsed))
        {
            return $"字段 {fieldName} 需要无符号整数。";
        }

        return parsed > max ? $"字段 {fieldName} 超出范围：0..{max}。" : null;
    }

    private void LogTableValidation(HexTableValidationResult validation)
    {
        Log(new string('-', 80));
        Log($"表：{validation.Table.Id} {validation.Table.TableName}");
        Log($"文件：{validation.FilePath}");
        Log($"文件存在：{validation.FileExists}，长度：{validation.FileLength}，结束偏移：{validation.Table.EndOffsetExclusive}");
        Log($"列/Bytes 匹配：{validation.ColumnsMatchBytes}，范围有效：{validation.FitsInFile}，保留/未命名字节：{validation.PaddingBytes}");
        foreach (var warning in validation.Warnings)
        {
            Log("警告：" + warning);
        }
    }

    private void CreateTestCopy()
    {
        if (_project == null) return;
        try
        {
            Cursor = Cursors.WaitCursor;
            var progress = new Progress<string>(msg => SetStatus(msg));
            var path = _backupManager.CreateTestCopy(_project, progress);
            Log("已创建测试副本：" + path);
            SetStatus("测试副本创建完成");
            if (MessageBox.Show(this, "测试副本已创建，是否切换到该副本进行编辑？\r\n" + path, "完成", MessageBoxButtons.YesNo, MessageBoxIcon.Information) == DialogResult.Yes)
            {
                LoadProject(_projectDetector.CreateProjectFromGameRoot(path));
            }
        }
        catch (Exception ex)
        {
            Log("创建测试副本失败：" + ex);
            MessageBox.Show(this, ex.Message, "创建测试副本失败", MessageBoxButtons.OK, MessageBoxIcon.Error);
        }
        finally
        {
            RefreshWorkflowGuide(updateStatus: false);
            Cursor = Cursors.Default;
        }
    }

    private void RunProjectAudit()
    {
        if (_project == null)
        {
            MessageBox.Show(this, "请先加载项目。", "提示", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            return;
        }

        try
        {
            Cursor = Cursors.WaitCursor;
            _currentAuditItems = _projectAuditService.Analyze(_project, _tables);
            _auditGrid.DataSource = new BindingList<ProjectAuditItem>(_currentAuditItems.ToList());
            foreach (DataGridViewRow row in _auditGrid.Rows)
            {
                if (row.DataBoundItem is not ProjectAuditItem item) continue;
                row.DefaultCellStyle.BackColor = item.Severity switch
                {
                    "Error" => Color.MistyRose,
                    "Warn" => Color.LemonChiffon,
                    _ => row.DefaultCellStyle.BackColor
                };
            }

            var errors = _currentAuditItems.Count(x => x.Severity == "Error");
            var warnings = _currentAuditItems.Count(x => x.Severity == "Warn");
            _auditInfoBox.Text =
                $"项目：{_project.GameRoot}\r\n" +
                $"体检项：{_currentAuditItems.Count}    错误：{errors}    警告：{warnings}\r\n" +
                (errors == 0
                    ? "没有发现阻断性问题。仍建议所有修改先进入测试副本。"
                    : "存在阻断性问题，请先处理红色项。");
            _writeAuditReportButton.Enabled = _currentAuditItems.Count > 0;
            Log($"项目体检完成：错误 {errors}，警告 {warnings}。");
            SetStatus($"项目体检完成：错误 {errors}，警告 {warnings}");
            RefreshWorkflowGuide(updateStatus: false);
        }
        catch (Exception ex)
        {
            _auditInfoBox.Text = ex.ToString();
            Log("项目体检失败：" + ex);
            MessageBox.Show(this, ex.Message, "项目体检失败", MessageBoxButtons.OK, MessageBoxIcon.Error);
        }
        finally
        {
            Cursor = Cursors.Default;
        }
    }

