        if (IsCurrentTab("关卡地图联动") && _scenarioMapLinkGrid.CurrentRow?.DataBoundItem is ScenarioMapLinkInfo mapLink)
        {
            return (
                "关卡地图联动",
                BuildScenarioMapLinkCreatorNoteTargetKey(mapLink),
