        {
            MessageBox.Show(this, "请先点击“读取 RS/Map .eex”建立 EEX 索引。", "提示", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            return;
        }

        try
        {
            Cursor = Cursors.WaitCursor;
