            : $"选中候选：{selectedUnit.Category}，{selectedUnit.SourceCommand}，{selectedUnit.SceneSection}，偏移 {selectedUnit.OffsetHex}\r\n人物：{selectedUnit.PersonHint}\r\n坐标：{selectedUnit.CoordinateHint}\r\n阵营：{selectedUnit.FactionHint}\r\nAI：{selectedUnit.AiHint}\r\n核对状态：{selectedUnit.ReviewStatus}\r\n创作者备注：{selectedUnit.CreatorMemo}";

        return (
            "战场制作",
            $"Battlefield#{document.Scenario.FileName}",
            $"{document.Scenario.FileName} 战场制作备注",
            "从战场制作页创建；用于记录关卡地图、胜败条件、出场单位、坐标、阵营和 AI 核对。",
            $"关卡：{document.Scenario.FileName}\r\n" +
            $"地图：{mapText}\r\n" +
            $"标题：{_battlefieldTitleBox.Text}\r\n" +
            $"胜败条件：\r\n{_battlefieldConditionsBox.Text}\r\n\r\n" +
            $"{unitText}\r\n\r\n" +
            "修改意图：\r\n" +
            "旧工具对照：\r\n" +
            "实机验证：\r\n" +
            "回滚点/备份：");
    }

    private void SaveBattlefieldUnitReviews()
    {
        if (_project == null || _currentBattlefieldDocument == null)
        {
            MessageBox.Show(this, "请先读取一个战场关卡。", "提示", MessageBoxButtons.OK, MessageBoxIcon.Information);
            return;
        }

        try
        {
            _battlefieldUnitGrid.EndEdit();
            var rows = _currentBattlefieldDocument.UnitCandidates.ToList();
            var path = _battlefieldUnitReviewService.Save(_project, _currentBattlefieldDocument, rows);
            _battlefieldInfoBox.Text = BuildBattlefieldInfo(_currentBattlefieldDocument) +
                                       $"\r\n\r\n出场/坐标候选核对状态已保存：{path}\r\n说明：该文件是项目侧 JSON，不写入 R/S eex，不参与发布封包。";
            SetStatus($"战场制作：已保存出场核对 {rows.Count} 条");
            Log($"已保存战场出场核对：{_currentBattlefieldDocument.Scenario.FileName} path={path}");
            MessageBox.Show(this, $"出场/坐标候选核对状态已保存。\r\n{path}", "保存出场核对完成", MessageBoxButtons.OK, MessageBoxIcon.Information);
        }
        catch (Exception ex)
        {
            Log("保存战场出场核对失败：" + ex);
            MessageBox.Show(this, ex.Message, "保存出场核对失败", MessageBoxButtons.OK, MessageBoxIcon.Error);
        }
    }

    private void SaveBattlefieldTexts()
    {
        if (_project == null || _currentBattlefieldDocument == null)
        {
            MessageBox.Show(this, "请先读取一个战场关卡。", "提示", MessageBoxButtons.OK, MessageBoxIcon.Information);
            return;
        }

        var errors = new List<string>();
        var titleError = BattlefieldEditorService.ValidateTextForEntry(_currentBattlefieldDocument.TitleEntry, _battlefieldTitleBox.Text, "关卡标题");
        if (_currentBattlefieldDocument.TitleEntry != null && titleError != null) errors.Add(titleError);
        var conditionError = BattlefieldEditorService.ValidateTextForEntry(_currentBattlefieldDocument.ConditionEntry, _battlefieldConditionsBox.Text, "胜败条件");
        if (_currentBattlefieldDocument.ConditionEntry != null && conditionError != null) errors.Add(conditionError);
        if (errors.Count > 0)
        {
            MessageBox.Show(this, string.Join("\r\n", errors), "文本容量校验失败", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            return;
        }

        var changed = false;
        if (_currentBattlefieldDocument.TitleEntry != null)
        {
            changed |= !string.Equals(
                BattlefieldEditorService.NormalizeText(_battlefieldTitleBox.Text),
                BattlefieldEditorService.NormalizeText(_currentBattlefieldDocument.TitleEntry.OriginalText),
                StringComparison.Ordinal);
        }

        if (_currentBattlefieldDocument.ConditionEntry != null)
        {
            changed |= !string.Equals(
                BattlefieldEditorService.NormalizeText(_battlefieldConditionsBox.Text),
                BattlefieldEditorService.NormalizeText(_currentBattlefieldDocument.ConditionEntry.OriginalText),
                StringComparison.Ordinal);
        }

        if (!changed)
        {
            MessageBox.Show(this, "标题和胜败条件没有检测到改动。", "无需保存", MessageBoxButtons.OK, MessageBoxIcon.Information);
            return;
        }

        if (MessageBox.Show(this,
                $"即将写入 RS\\{_currentBattlefieldDocument.Scenario.FileName}。\r\n\r\n当前仅写回已匹配的标题/胜败条件文本，未知命令结构保持原样；保存前自动备份，保存后复读校验。是否继续？",
                "确认保存战场文本",
                MessageBoxButtons.YesNo,
                MessageBoxIcon.Question) != DialogResult.Yes)
        {
            return;
        }

        try
        {
            Cursor = Cursors.WaitCursor;
            var scenarioFileName = _currentBattlefieldDocument.Scenario.FileName;
            var result = _battlefieldEditorService.SaveTitleAndConditions(
                _project,
                _currentBattlefieldDocument,
                _battlefieldTitleBox.Text,
                _battlefieldConditionsBox.Text);
            var reread = _scenarioTextReader.Read(result.FilePath);
            if (_currentBattlefieldDocument.TitleEntry != null)
            {
                VerifyBattlefieldText(reread, _currentBattlefieldDocument.TitleEntry.Offset, _battlefieldTitleBox.Text, "标题");
            }
            if (_currentBattlefieldDocument.ConditionEntry != null)
            {
                VerifyBattlefieldText(reread, _currentBattlefieldDocument.ConditionEntry.Offset, _battlefieldConditionsBox.Text, "胜败条件");
            }

            EnsureBattlefieldBaseDataLoaded();
            var scenario = _currentScenarioFiles.First(x => x.FileName.Equals(scenarioFileName, StringComparison.OrdinalIgnoreCase));
            _currentBattlefieldDocument = _battlefieldEditorService.Load(_project, scenario, _currentSceneStringDocument ?? TryReadSceneDictionaryForProbe(), _tables, _currentScenarioMapLinks);
            _battlefieldUnitReviewService.Apply(_project, _currentBattlefieldDocument);
            _battlefieldTitleBox.Text = _currentBattlefieldDocument.TitleEntry?.Text ?? scenario.TitleHint;
            _battlefieldConditionsBox.Text = _currentBattlefieldDocument.ConditionEntry?.Text ?? string.Empty;
            PopulateBattlefieldUnitCategoryFilter(_currentBattlefieldDocument.UnitCandidates);
            BindBattlefieldUnitCandidates(_currentBattlefieldDocument.UnitCandidates);
            BindBattlefieldCommandCandidates(_currentBattlefieldDocument.CommandCandidates);
            UpdateBattlefieldCapacityLabels();
            _battlefieldInfoBox.Text =
                BuildBattlefieldInfo(_currentBattlefieldDocument) +
                $"\r\n\r\n保存完成：写入 {result.EntriesWritten} 条，变化 {result.ChangedBytes} 字节。\r\n备份：{result.BackupPath}\r\n报告：{result.ReportJsonPath}";
            Log($"已保存战场文本：{scenarioFileName} entries={result.EntriesWritten} backup={result.BackupPath}");
            SetStatus($"战场制作保存完成：{scenarioFileName}");
            MessageBox.Show(this, $"保存完成。\r\n备份：{result.BackupPath}\r\n报告：{result.ReportJsonPath}", "战场制作保存完成", MessageBoxButtons.OK, MessageBoxIcon.Information);
        }
        catch (Exception ex)
        {
            Log("保存战场制作文本失败：" + ex);
            MessageBox.Show(this, ex.Message, "保存战场制作失败", MessageBoxButtons.OK, MessageBoxIcon.Error);
        }
        finally
        {
            Cursor = Cursors.Default;
        }
    }

    private static void VerifyBattlefieldText(IReadOnlyList<ScenarioTextEntry> reread, int offset, string expectedText, string displayName)
    {
        var actual = reread.FirstOrDefault(x => x.Offset == offset);
        var expected = BattlefieldEditorService.NormalizeText(expectedText);
        if (actual == null || !BattlefieldEditorService.NormalizeText(actual.Text).Equals(expected, StringComparison.Ordinal))
        {
            throw new InvalidOperationException($"{displayName}保存后复读校验失败：期望“{expected}”，实际“{actual?.Text ?? "<未找到>"}”。");
        }
    }

    private void JumpBattlefieldMapMaker()
    {
        var link = _currentBattlefieldDocument?.MapLink;
        if (link == null || !link.MapImageExists)
        {
            MessageBox.Show(this, "当前关卡没有可跳转的地图图片。", "提示", MessageBoxButtons.OK, MessageBoxIcon.Information);
            return;
        }

        SelectTabPageByText("地图制作");
        if (_mapImageList.Items.Count == 0) LoadMapImages();
        if (!SelectMapImageByName(link.MapImageName))
        {
            MessageBox.Show(this, "地图制作列表中没有找到对应地图图片。", "提示", MessageBoxButtons.OK, MessageBoxIcon.Information);
        }
    }

    private void JumpBattlefieldScenarioStructure()
    {
        var scenario = _currentBattlefieldDocument?.Scenario;
        if (scenario == null) return;
        SelectTabPageByText("R/S eex高级探针");
        SelectScenarioFileForNavigation(scenario.FileName);
        BuildSelectedScenarioStructure();
    }

    private async Task LoadScriptScenariosAsync()
    {
        if (_loadingScriptScenarioList) return;
        if (_project == null)
        {
            MessageBox.Show(this, "\u8bf7\u5148\u52a0\u8f7d\u9879\u76ee\u3002", "\u63d0\u793a", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            return;
        }

        try
        {
            _loadingScriptScenarioList = true;
            _loadScriptButton.Enabled = false;
            _scriptScenarioCombo.Enabled = false;
            Cursor = Cursors.WaitCursor;
            SetStatus("\u5267\u672c\u5236\u4f5c\uff1a\u6b63\u5728\u8bfb\u53d6\u5267\u672c\u7d22\u5f15...");
            _scriptDetailBox.Text = "\u6b63\u5728\u8bfb\u53d6 RS \u76ee\u5f55 R/S eex \u5267\u672c\u7d22\u5f15\u3002\u4e3a\u907f\u514d\u754c\u9762\u5361\u6b7b\uff0c\u672c\u6b65\u9aa4\u53ea\u8bfb\u53d6\u6587\u4ef6\u540d\u3001\u7f16\u53f7\u548c\u957f\u5ea6\uff1b\u9009\u62e9\u5177\u4f53\u5267\u672c\u540e\u518d\u89e3\u6790\u547d\u4ee4\u6811\u4e0e\u6587\u672c\u3002";
            await Task.Yield();

            var project = _project;
            var rows = await Task.Run(() => new ScenarioFileReader()
                .ReadAllIndex(project)
                .Where(x => ScenarioFileReader.IsRsScriptFile(x.FileName))
                // 按传统流程排序：R_00..R_nn 在前，S_00..S_nn 在后；同类内按数字排序。
                .OrderBy(x => ScenarioFileReader.IsBattlefieldScriptFile(x.FileName) ? 1 : 0)
                .ThenBy(x => int.TryParse(x.Id, NumberStyles.Integer, CultureInfo.InvariantCulture, out var id) ? id : int.MaxValue)
                .ThenBy(x => x.FileName, StringComparer.CurrentCultureIgnoreCase)
                .ToList());

            _updatingScriptScenarioSelection = true;
            _scriptScenarioCombo.DataSource = new BindingList<ScenarioFileInfo>(rows);
            _scriptScenarioCombo.DisplayMember = nameof(ScenarioFileInfo.FileName);
            _scriptScenarioCombo.ValueMember = nameof(ScenarioFileInfo.FileName);
            _scriptScenarioCombo.SelectedIndex = -1;
            _updatingScriptScenarioSelection = false;

            ClearScriptDocumentView();
            _scriptDetailBox.Text = rows.Count > 0
                ? $"\u5df2\u8bfb\u53d6\u5267\u672c\u7d22\u5f15\uff1a{rows.Count} \u4e2a\u3002\u8bf7\u5728\u4e0a\u65b9\u4e0b\u62c9\u6846\u9009\u62e9\u8981\u7f16\u8f91/\u67e5\u770b\u7684 R/S eex \u5267\u672c\uff1b\u9009\u62e9\u540e\u4f1a\u540e\u53f0\u89e3\u6790\u547d\u4ee4\u6811\u548c\u6587\u672c\u3002"
                : "\u5267\u672c\u5236\u4f5c\uff1a\u6ca1\u6709\u627e\u5230 R/S eex \u5267\u672c\u6587\u4ef6\u3002";
            _scriptHeaderLabel.Text = $"字典：{(_currentSceneStringDocument == null ? "未加载" : "已加载")}    剧本：未选择    列表：{rows.Count}";
            SetStatus($"\u5267\u672c\u5236\u4f5c\uff1a\u5df2\u8bfb\u53d6\u5267\u672c\u7d22\u5f15 {rows.Count} \u4e2a");
        }
        catch (Exception ex)
        {
            _updatingScriptScenarioSelection = false;
            _scriptDetailBox.Text = ex.ToString();
            Log("Load script scenario index failed: " + ex);
            MessageBox.Show(this, ex.Message, "\u8bfb\u53d6\u5267\u672c\u7d22\u5f15\u5931\u8d25", MessageBoxButtons.OK, MessageBoxIcon.Error);
        }
        finally
        {
            _loadingScriptScenarioList = false;
            _loadScriptButton.Enabled = true;
            _scriptScenarioCombo.Enabled = true;
            Cursor = Cursors.Default;
        }
    }

    private async Task LoadSelectedScriptScenarioAsync()
    {
        if (_updatingScriptScenarioSelection || _loadingScriptScenarioDocument) return;
        if (_project == null) return;
        if (_scriptScenarioCombo.SelectedItem is not ScenarioFileInfo scenario) return;

        try
        {
            _loadingScriptScenarioDocument = true;
            _scriptScenarioCombo.Enabled = false;
            Cursor = Cursors.WaitCursor;
            SetStatus($"\u5267\u672c\u5236\u4f5c\uff1a\u6b63\u5728\u8bfb\u53d6 {scenario.FileName}...");
            await Task.Yield();
            var dictionary = _currentSceneStringDocument ?? TryReadSceneDictionaryForProbe();
            if (dictionary == null)
            {
                MessageBox.Show(this, $"未找到 CczString.ini：{ProjectDetector.FindSceneDictionaryPath(_project)}\r\n\r\n无法按传统命令名生成剧本树。跨设备迁移时，请把旧版 a新剧本编辑器v0.23 目录随工具包一起复制。", "缺少剧本字典", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                return;
            }
            PopulateScriptNewCommandCombo(dictionary);

            var project = _project;
            var tables = _tables;
            var result = await Task.Run(() =>
            {
                LegacyScenarioDocument? legacy = null;
                try
                {
                    legacy = new LegacyScenarioReader().Read(scenario.Path, dictionary);
                }
                catch
                {
                    // Non-standard files still fall back to the existing probe workflow.
                }

                if (legacy != null)
                {
                    return (
                        Legacy: legacy,
                        Structure: (ScenarioStructureProbeResult?)null,
                        Texts: (IReadOnlyList<ScenarioTextEntry>?)null);
                }

                var structure = new ScenarioStructureProbeReader().Build(scenario.Path, dictionary, maxCommandRows: 600, project: project, tables: tables);
                var texts = new ScenarioTextReader().Read(scenario.Path);
                return (
                    Legacy: (LegacyScenarioDocument?)null,
                    Structure: structure,
                    Texts: (IReadOnlyList<ScenarioTextEntry>)texts);
            });

            var refreshDefaultSelectionAfterLoad = false;
            _bindingScriptDocument = true;
            SuspendLayout();
            _scriptTree.SuspendLayout();
            _scriptCommandGrid.SuspendLayout();
            _scriptParameterGrid.SuspendLayout();
            _scriptTextGrid.SuspendLayout();
            _scriptSearchResultGrid.SuspendLayout();
            try
            {
                _currentScriptScenario = scenario;
                _selectedScriptCommandRow = null;
                _selectedScriptTextEntry = null;
                _currentLegacyScriptDocument = result.Legacy;
                if (_currentLegacyScriptDocument != null)
                {
                    _currentScriptStructure = BuildLegacyScriptStructureResult(_currentLegacyScriptDocument);
                    _currentScriptTextEntries = BuildLegacyScriptTextEntries(_currentLegacyScriptDocument);
                }
                else
                {
                    _legacyScriptCommandByKey.Clear();
                    _legacyScriptRowByKey.Clear();
                    _legacyScriptTextByOffset.Clear();
                    _legacyScriptTextEntryByOffset.Clear();
                    _currentScriptStructure = result.Structure ?? throw new InvalidOperationException("剧本结构读取失败。");
                    _currentScriptTextEntries = result.Texts ?? Array.Empty<ScenarioTextEntry>();
                }

                var modeText = _currentLegacyScriptDocument != null ? "旧版完整树" : "兼容探针";
                _scriptHeaderLabel.Text = $"字典：已加载    剧本：{scenario.FileName}    模式：{modeText}    命令：{_currentScriptStructure.Rows.Count(x => x.NodeType == "Command候选")}    文本：{_currentScriptTextEntries.Count}";
                BuildScriptTree(_currentScriptStructure, _currentScriptTextEntries);
                BindScriptCommandRows(Array.Empty<ScenarioStructureRow>());
                BindScriptParameterRows(Array.Empty<ScenarioCommandParameterRow>());
                BindScriptTextRows(_currentScriptTextEntries);
                _currentScriptSearchResults = Array.Empty<ScenarioSearchResultRow>();
                BindScriptSearchResultRows(_currentScriptSearchResults);
                _scriptTextEditorBox.Clear();
                UpdateScriptTextCapacityLabel();
                _saveScriptTextButton.Enabled = false;
                _saveScriptStructureButton.Enabled = _currentLegacyScriptDocument != null;
                _createScriptNoteButton.Enabled = true;
                _jumpScriptBattlefieldButton.Enabled = true;
                _locateScriptCommandButton.Enabled = true;
                _copyScriptCommandButton.Enabled = true;
                _previewPasteScriptCommandButton.Enabled = _scriptCommandClipboardItem != null;
                UpdateScriptStructureEditButtons();
                if (SelectDefaultScriptTreeNode())
                {
                    refreshDefaultSelectionAfterLoad = true;
                }
                else
                {
                    _scriptDetailBox.Text = BuildScriptOverview(_currentScriptStructure, _currentScriptTextEntries);
                }
            }
            finally
            {
                _scriptSearchResultGrid.ResumeLayout();
                _scriptTextGrid.ResumeLayout();
                _scriptParameterGrid.ResumeLayout();
                _scriptCommandGrid.ResumeLayout();
                _scriptTree.ResumeLayout();
                ResumeLayout(true);
                _bindingScriptDocument = false;
            }
            if (refreshDefaultSelectionAfterLoad)
            {
                ShowSelectedScriptTreeNode();
            }
            SetStatus($"\u5267\u672c\u5236\u4f5c\uff1a{scenario.FileName}");
        }
        catch (Exception ex)
        {
            _scriptDetailBox.Text = ex.ToString();
            Log("Load script document failed: " + ex);
            MessageBox.Show(this, ex.Message, "\u8bfb\u53d6\u5267\u672c\u5236\u4f5c\u5931\u8d25", MessageBoxButtons.OK, MessageBoxIcon.Error);
        }
        finally
        {
            _loadingScriptScenarioDocument = false;
            _scriptScenarioCombo.Enabled = true;
            Cursor = Cursors.Default;
        }
    }

